	ApplyRollOutcome(context.Context, *ApplyRollOutcomeRequest) (*ApplyRollOutcomeResponse, error)
	// Apply an attack outcome from a resolved action roll.
	ApplyAttackOutcome(context.Context, *DaggerheartApplyAttackOutcomeRequest) (*DaggerheartApplyAttackOutcomeResponse, error)
	// Apply an adversary attack outcome from a resolved adversary roll.
	ApplyAdversaryAttackOutcome(context.Context, *DaggerheartApplyAdversaryAttackOutcomeRequest) (*DaggerheartApplyAdversaryAttackOutcomeResponse, error)
	// Apply a reaction outcome from a resolved reaction roll.
	ApplyReactionOutcome(context.Context, *DaggerheartApplyReactionOutcomeRequest) (*DaggerheartApplyReactionOutcomeResponse, error)
	// Apply a level-up to a character (progression).
	ApplyLevelUp(context.Context, *DaggerheartApplyLevelUpRequest) (*DaggerheartApplyLevelUpResponse, error)
	// Apply a class feature activation or stateful class choice.
	ApplyClassFeature(context.Context, *DaggerheartApplyClassFeatureRequest) (*DaggerheartApplyClassFeatureResponse, error)
	ApplySubclassFeature(context.Context, *DaggerheartApplySubclassFeatureRequest) (*DaggerheartApplySubclassFeatureResponse, error)
	TransformBeastform(context.Context, *DaggerheartTransformBeastformRequest) (*DaggerheartTransformBeastformResponse, error)
	DropBeastform(context.Context, *DaggerheartDropBeastformRequest) (*DaggerheartDropBeastformResponse, error)
	BeginCompanionExperience(context.Context, *DaggerheartBeginCompanionExperienceRequest) (*DaggerheartBeginCompanionExperienceResponse, error)
	ReturnCompanion(context.Context, *DaggerheartReturnCompanionRequest) (*DaggerheartReturnCompanionResponse, error)
	// Update a character's gold denominations (inventory).
	UpdateGold(context.Context, *DaggerheartUpdateGoldRequest) (*DaggerheartUpdateGoldResponse, error)
	// Acquire a domain card into a character's vault or loadout (inventory).
	AcquireDomainCard(context.Context, *DaggerheartAcquireDomainCardRequest) (*DaggerheartAcquireDomainCardResponse, error)
	// Swap equipment between active/inventory/none slots (inventory).
	SwapEquipment(context.Context, *DaggerheartSwapEquipmentRequest) (*DaggerheartSwapEquipmentResponse, error)
	// Use a consumable, decrementing its quantity (inventory).
	UseConsumable(context.Context, *DaggerheartUseConsumableRequest) (*DaggerheartUseConsumableResponse, error)
	// Acquire a consumable, incrementing its quantity (inventory).
	AcquireConsumable(context.Context, *DaggerheartAcquireConsumableRequest) (*DaggerheartAcquireConsumableResponse, error)
	// Apply a direct character state patch (HP, Hope, Stress, Armor).
	ApplyCharacterStatePatch(context.Context, *DaggerheartApplyCharacterStatePatchRequest) (*DaggerheartApplyCharacterStatePatchResponse, error)
	// Add or remove stat modifiers on a character (evasion, thresholds, etc.).
	ApplyStatModifiers(context.Context, *DaggerheartApplyStatModifiersRequest) (*DaggerheartApplyStatModifiersResponse, error)
